import os, base64, gzip
base = os.path.dirname(os.path.abspath(__file__))
FILES = [
  ('src\\\\app\\\\admin-loja\\\\page.tsx', ''),
  ('src\\\\app\\\\api\\\\admin\\\\blog\\\\route.ts', ''),
  ('src\\\\app\\\\api\\\\admin\\\\blog\\\\[id]\\\\route.ts', ''),
  ('src\\\\app\\\\api\\\\admin\\\\blog\\\\comentarios\\\\route.ts', ''),
]
ok = 0
for rel, data in FILES:
    try:
        dest = os.path.join(base, rel)
        os.makedirs(os.path.dirname(dest), exist_ok=True)
        with open(dest, "w", encoding="utf-8", newline="\n") as f:
            f.write(gzip.decompress(base64.b64decode(data)).decode("utf-8"))
        print("OK:", rel)
        ok += 1
    except Exception as e:
        print("ERRO:", rel, e)
print()
print(f"Total: {ok}/4 arquivos instalados")
print("Admin Blog completo com moderacao e videos!")
print("Rode: npm run build")